mapper.select:
SELECT kp.id AS knowledgePointId, kp.name AS knowledgePointName, COUNT(ua.id) AS totalCount, SUM(CASE WHEN ua.is_correct = 0 THEN 1 ELSE 0 END) AS wrongCount, ROUND(SUM(CASE WHEN ua.is_correct = 1 THEN 1 ELSE 0 END) / COUNT(ua.id), 4) AS accuracyRate FROM user_answer ua JOIN question_bank qb ON qb.id = ua.question_id JOIN knowledge_point kp ON kp.id = qb.knowledge_point_id JOIN `user` u ON u.id = ua.user_id
ua.user_id IN
#{id}
AND qb.knowledge_point_id IN
#{id}
AND u.class_name = #{className}
GROUP BY kp.id, kp.name ORDER BY accuracyRate ASC, wrongCount DESC
